import{c as p,Q as a,j as i,m as c}from"./chunks/framework.hhGiamYR.js";const n=JSON.parse('{"title":"致尼科洛","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/upper/47-致尼科洛.md","filePath":"research/machiavelli/machiavelli/diplomatic/upper/47-致尼科洛.md"}'),l={name:"research/machiavelli/machiavelli/diplomatic/upper/47-致尼科洛.md"};function t(r,e,o,m,_,s){return a(),i("div",null,[...e[0]||(e[0]=[c('<h1 id="致尼科洛" tabindex="-1">致尼科洛 <a class="header-anchor" href="#致尼科洛" aria-label="Permalink to &quot;致尼科洛&quot;">​</a></h1><p>致尼科洛 · 马基雅维利，出使法国笃信王陛下 1503/1504年1月19日决议</p><p>尼科洛，你应该通过驿道取道米兰赶往里昂，或者你所知道能够遇到</p><p>马基雅维利全集 Opere complete di Niccolo Machiavelli</p><p>笃信王陛下的地方。你要带上2封国书， 一封致法国国王陛下，另一封致 鲁昂枢机主教；另外2封国书则未写抬头，你可以在最需要的时候使用。 另一封信是给我们在那里的大使尼科洛 · 瓦洛里的，在你到达的时候， 一 定要同他交谈，阐明我们给你布置的全部出使任务。你可以同他畅所欲 言，以使他能够充分了解你此行的目的，而他也能够告诉你那里发生的一 切，以及在离开此地之后他在那里所了解到的各种情况。此后，你们要 一同去面见国王陛下，并向他禀报以上我们提到的所有要点。我们尤其 希望国王陛下能充分地了解并且理解与之相关的全部情形，不要疏忽任何 部分，要使我们的笃信王陛下完全明白我们这里的形势，以及能使其好转 的办法；并且，为使我们的城邦免于灭顶之灾，看清楚陛下的计划、听清 楚陛下的想法，对我们非常必要。你此行的任务之一就是亲眼看看他们准 备的情况，并立刻将所见所闻写信告知我们；同时，也请加上你自己对它 们的猜测和判断。而如果这些准备情况在性质上不足以让我们有所倚靠， 或者它们可能微不足道、捉摸不定或拖沓延误，此时你就一定要让国王陛 下明白，单靠我们的力量无论如何都无法提供安全，我们要的援助一定是 大规模的、迅速及时的和真实的，我们只有等待和依靠这样的援助才是明 智的。你也不必仅仅这么做，反而要展现出，我们正全力以赴并迫不及待 地向任何可能的地方寻求援助，因为我们必须保全我们共和国不致灭亡。 这优先于其他任何方面的考虑。已经没有多少自由留给我城了，我们必须 全力以赴捍卫我们的这点自由。为了达到这个目的，你必须在适当的场合 和时机向国王陛下解释清楚，我们正处于危急存亡之秋； 一方面，威尼斯 人正步步紧逼，另一方面，西班牙人也蠢蠢欲动，他们狼狈为奸，相互配 合。你必须让国王陛下充分理解我们面临的处境，我们一方面陷入比萨的 战争之中，另一方面，威尼斯人在罗马涅的一支军队已经大兵压境。而我 们所有的邻国素来与我们交恶，自从法国最近战败之后，或者自从同西班 牙人签署停战协约以后，益发如此，或者正打算如此；我们兵力有限，分 散在上述不同区域，且在为国王陛下效力时在那不勒斯王国受到重创；在</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>这些事情上，我们不必给你特别的指示，因为你在逗留期间可以很好地熟 悉所有这些内容；对于在罗马涅发生的事情也是如此。我们想要从罗马方 面知道西班牙人的决心，以及我们可以从教皇身上得到多少微薄的希望。 在任何事情上，如果你缺少信息，可以从尼科洛 · 瓦洛里那里得到，因为 我们已经在给他的信中写明了一切，并为他寄去了所有的书面文件，他现 在很有可能已经收到了这些材料。你还可以陈述我们面临的危险，并宣布 我们的敌人包藏祸心，还要提到反对我们的叛乱者已经到了卡斯泰洛和锡 耶纳；在讲述所有这些事情及其相关的情境的时候，你表达的方式必须是 取得显著效果的，最终使得国王陛下得出这样的结论：我们派遣你出使， 就是为了了解他的意愿，和了解国王手中还拥有的并旨在维持其盟友的措 施准备情况。你还要向他表示，伦巴第的威胁也不可小觑。国王陛下必须 采取积极有效的应对措施，并且要以充分的手段向所有人证明，他能够而 且愿意拯救这两个邦国。最后，你要表明，我们希望国王陛下能出出主 意，帮助保全我们和我们的国家。我们相信，对这些问题的答复将是强有 力的，一定会有足够的计划、谋略。然而，我们的想法以及我们对此的评 价是这样的：这些计划和措施不能满足我们，但要紧的是它们必须能解燃 眉之急，并且在性质上能够使无论国王陛下的盟友还是他的敌人都不敢对 他的国家和我们的城邦轻举妄动；除非给予我们的支援具有这样的性质， 否则，我们就要面临被攻击的危险，而这是我们极力避免的。我们不想被 迫去通过其他的手段来寻求自己的安全，正如我们永远不想背弃我们同国 王的友谊，而是愿意同国王陛下同甘苦、共患难，只要我们能够看见一条 确切的城邦救赎之道。你必须向尼科洛 · 瓦洛里说清楚我们此次派你出 使的主要原因。我们昨天收到了一封来自亚历山德罗的信，信中告知詹保 罗 · 巴廖尼的服役合同①已经终止了，因此，对于每一笔交易，我们都要 支付10000斯库多；而我们的信件也被扣留了。所有这些都表明， 一是我</p><p>①詹保罗 · 巴廖尼的军事服役合同是以佛罗伦萨人的名义同他签订的，但是为了法国国王路易十二的原 因去打仗但他是为法国国王路易十二打仗。这件事在上一次出使罗马的任务中曾被提到。 —英译本注</p><p>Opere complete di Niccolo Machiavelli</p><p>们的利益被完全弃之不顾，二是他们为了自己利益而抛弃盟友，使盟友任 由敌人蹂躏宰割；此外，他们完全不念我们的赤胆忠心和劳苦功高。鉴 于这些事情非常重要，我们认为值得一说，裨使他们了解，我们觉得有 必要终止这份服役合同，个中缘由，你自己非常清楚，而且我们在给尼科 洛 · 瓦洛里的信中也提过多次。至于10000斯库多的钱款，我们不会背信 弃义，也不会疏于职责，但我们不可能再承担任何新的花费来加重负担 了。由于这个服役合同是基于他们的理由并由他们提出的，我们不能承担 这两个责任中的任何一个，他们必须免除我们在此事上的责任。如果你被 问到，难道我们就没有批准过这份服役合同吗?你就回答说，尽管这件事 是这么决定的，而且这也是我们答应枢机主教的，但我们在这件事上考虑 不多，只是觉得出于荣誉，我们有必要下决心做出承诺。除此之外，我们 认为事情应该如此安排，以使我们能保持信心并遵守承诺，然而， 一旦我 们受到攻击而看不到救援，我们就无法承担责任了；你应该进一步表示， 无论是终止巴廖尼的服役合同，还是免除我们在其他事情上的责任，相对 于我们所面临的种种危险都是杯水车薪；然而，最迫在眉睫的事情就是让 国王陛下醒悟过来，为我们提供援助，正如我们前面请求的。你还应该将 所有这些要点同至为尊贵的教皇特使沟通，还有内穆尔①以及所有那些在 这件事上能够帮助我们在国王陛下面前说上话的人。我们希望你能够兢兢 业业，将所有这些情况写下来，尽早将结果告知我们，并在你执行这项任 务的时候，尽可能多地掌握各种信息，然后回到你现在的岗位上，除非大 使另有安排。 在途经米兰的时候，你应该去拜访一下那位至为杰出的副帅大人，并 向他说明同样的事情，以便使他也能够提供帮助，尤其是让他意识到威尼 斯人对其邦国的种种威胁。他们近在咫尺，又受到显而易见的狂热想法所 驱动。至于来自西班牙人的危险，这是尽人皆知的。他们正调集军队，随</p><p>①皮埃尔 · 德 · 罗昂-盖梅内，即第一次出使法国宫廷时提到的吉斯元帅。 ——中译者注</p><p>时整备发动新的攻势。最为有效的措施之一，就是保住托斯卡纳来对付这 种危险，保全她的生命直到她恢复自己的生命力，并能够恢复秩序；有关 你同他说的所有那些事情，你都要尽力促使他给国王陛下写信，因为经验 表明，很少有谋臣能够像国王陛下的副官一样对陛下施加更大的影响力。尼 科洛，我们笼统地向你解释了我们对你的要求，并向你布置了这样的任务： 请求国王陛下能够在我们处于重重危险之中的时候，给予我们帮助并向我们 建议应对之法。根据我们的判断，除非你被特别地问起，否则就不需要再说 别的什么了。如果说，在他们愿意为我们提供援助的情况下，你被要求必须 去说明我方考虑过了什么样的措施的话，你必须回答；根据我们的判断，首 先是国王陛下亲自越过阿尔卑斯山，并一路开到米兰，并不断地派后续部队 到那里；至于已经在那里的这些和那些部队，也要如此集合起来，并部署到 没有任何危险的地区。国王陛下威名远扬，定能将托斯卡纳全部邦国都团结 起来。陛下应该雇佣科隆纳家族或奥尔西尼家族的人为他效力，如果不能 雇佣全部，至少应该雇佣一部分，比如巴廖尼，从而增强自身的势力。光是 通过雇佣巴廖尼，就可以将锡耶纳揽入怀中，所以这是值得加以考虑的事。 他还应该将其舰队置于我城附近的海面上，并努力寻求让教皇陛下公开支持 他，除此之外，还要团结住瑞士人和其他人。我们已经在此前的信中提到过 这些了。我们的大使会将此事告知你。我们每天都与他保持通信联系，以便 使他能够清楚地了解所发生的每一件事，以及我们的全部想法。 发自市政宫，即日 马尔切洛 ·维尔吉利奥亲笔</p><p>信件1</p><p>伟大而杰出的诸位大人、我最为特别的主人： 我是于昨晚22点到达这里的，已经同肖蒙大人面谈过了，并向他说明</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>了我此次出使国王陛下的原因。由于我途经此地(米兰),因此这位领主 大人就能直接听到我谈论我要觐见国王陛下所说的事情，还有我要写给那 位国王的报告。我向他陈述了他的盟友以及他自己的那些邦国的利害关 系，向他证明了那些邦国正处于重重危机之中，以及应该采取的应对之 策。在向他解释完在给我的任务中提到的事情后，我还千方百计地向他暗 示，希望他明白我们多么需要援助，而这种援助必须看得见摸得着，正如 我们面临的威胁是看得见的那样。“因为如果诸位大人被抛弃了，你将看 到你的城邦被洗劫，并将看到她的完全毁灭；或者你不得不同那些强迫你 的人签署某种和约，其条件对你没有任何好处。”按照给我的任务，我谈 到了威尼斯人，谈到了佛罗伦萨的邻国和它们带来的混乱，以及国王保住 它们作为盟友是何等的必要，正如重新赢得那些已经失去的盟友是必要的 一样。事实上，我没有忘记向他陈述关于此事的所有利弊关系，让他知道 这些对他自己亦是事关重大，丝毫没有违背诸位大人给我的指示。有关你 们所面临的危险以及应该采取的措施，这位领主只是笼统地回答；首先， 他并不相信孔萨尔沃试图向前，其次，即使他确实这么做了，国王会很好 地照顾他的盟友以及他的邦国，你们不必为此事担忧，因为国王陛下是不 会食言的。我对他指出，这些事情都不足以让那些背后受到敌人威胁的人 感到安心。我还对他说，有证据表明，孔萨尔沃正准备对他采取行动。这 位领主说： “当孔萨尔沃看到了国王陛下在海上将其舰队的实力增加了一 倍，又得知了国王在伦巴第有一支庞大的军队，他无论如何也不敢再向前 进了。”我回答说，无论是海军舰队还是伦巴第的军队，都无法保卫托斯 卡纳。他对此的回答是，教皇会成为一个很好的法国人，詹保罗将成为他 们的雇佣军，而且锡耶纳会进行强有力的抵抗。我回答他说，无论是教皇 还是锡耶纳人都希望看到国王提供的援助，因为他们自己没有任何军队。 詹保罗要是能够为他们所雇佣当然很好，但是首先需要结束他的服役合 同；我还向他证明结束这个合同是多么重要，不但可以让他得到报酬，而 且能够让他为国家服务。我竭尽所能试图说服他，在意大利中，没有任何</p><p>城邦能够比佩鲁贾更适合成为抵御外敌的地方，只要在那里部署四五千步 兵以及四五百重骑兵。那个城市地势险要， 一旦有了这支精兵强将，就真 的是固若金汤，绝不能弃之不理；我竭尽所能地进一步劝他要守住那座城 市，这样一来，就能得到意大利其他地方的援军。在此之后，我们进入了 诸位大人同分散在意大利各处的邦国之间建立联盟关系的话题；然而，此 事需要法国国王陛下以其权威从中斡旋。就此问题以及我们以上讨论的问 题，诸位大人已经决定给国王陛下致信。我请求他派一个他自己的人同我 一起前往法国。他回答说，他会派出信使保持通信，并劝我尽一切努力早 日见到国王陛下，他相信国王会给予诸位大人满意的答复，让你们放心； 在我离开他的时候，他非常大声地对我说了一句话，周围的人都听得一清 二楚： “不要有怀疑。”①我忘了告诉诸位大人，他没有说过任何有关威 尼斯人的话，除了他说过他要让他们去参加钓鱼，并且他所指的肯定是瑞 士人。 以上就是我能从肖蒙大人那里得到的所有情况，并且我努力将他所说 的原话写下来寄给诸位大人。然后，我同来自佛罗伦萨的一个朋友谈了 谈。当我在宫殿碰到他的时候，他正好认出了我。他将我拉到了一旁，对 我说，感到非常遗憾。他对于法国国王的情况给予了非常糟糕的评价，因 为他知道国王此时手头根本无力弄到更多的钱；国王在这里只驻扎了少量 的骑兵，而且被部署在多个地点；国王没有步兵；提供步兵或是骑兵都需 要相当长的时间，没有任何迹象表明他们在此事上采取了任何措施。另一 方面，敌人正磨刀霍霍、枕戈待旦，携战胜之余威和好运，随时准备动 手；因此，他的确不知道国王陛下可以提供什么帮助，不仅对于其盟友如 此，甚至对于国王自己的国家亦是如此。此人忧心忡忡地对我说了所有这 一切，正如一个害怕而又不希望这些事发生的人一样。我在其他时候再将 这个人是谁写信告诉你们，这么做是为了安全起见，如果这封信发生什么</p><p>①原文为法文：Ne doutez de rien.。——中译者注</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>意外的话，我就不会对他造成伤害了。</p>',20)])])}const h=p(l,[["render",t]]);export{n as __pageData,h as default};
